IF NOT (EXISTS (SELECT 1 FROM eval.shipments WHERE BusinessKey='SHP-5004' AND Status='In Transit' AND CorrelationId='EVAL-SHIPPING-004') AND EXISTS (SELECT 1 FROM eval.shipment_milestones WHERE BusinessKey='DISCHARGE-SHP-5004' AND Status='Completed') AND EXISTS (SELECT 1 FROM eval.integration_messages WHERE CorrelationId='EVAL-SHIPPING-004' AND Status='Failed')) THROW 51001, 'Scenario defect not reproducible', 1; SELECT 'SHP-5004' ExpectedEntity, 'EVAL-SHIPPING-004' EvidenceValue; GO
